source .venv/bin/activate && python3 << 'PYEOF'
import requests, os

papers4 = [
    ("2212.09410", "jiang2023_gzip_text_classification"),
    ("2410.15280", "bao2024_neural_ncd_disconnect"),
]

for arxiv_id, filename in papers4:
    url = f"https://arxiv.org/pdf/{arxiv_id}.pdf"
    outpath = f"papers/{filename}.pdf"
    if os.path.exists(outpath):
        print(f"SKIP {outpath}")
        continue
    print(f"Downloading {arxiv_id} -> {outpath}...")
    try:
        r = requests.get(url, timeout=30)
        if r.status_code == 200 and len(r.content) > 1000:
            with open(outpath, 'wb') as f:
                f.write(r.content)
            print(f"  OK ({len(r.content)} bytes)")
        else:
            print(f"  FAILED status={r.status_code} size={len(r.content)}")
    except Exception as e:
        print(f"  ERROR: {e}")

print("\nAll papers in papers/:")
for f in sorted(os.listdir("papers")):
    if f.endswith('.pdf'):
        size = os.path.getsize(f"papers/{f}")
        print(f"  {f} ({size/1024:.0f} KB)")
PYEOF

python3 -c "
import importlib
for mod in ['fitz', 'PyPDF2', 'pypdf', 'pdfminer', 'pdfplumber', 'reportlab', 'pikepdf']:
    try:
        importlib.import_module(mod)
        print(f'{mod}: available')
    except:
        print(f'{mod}: not available')
"
